def is_safe_redirect_url(target):
    """Check if the redirect target is safe"""
    if not target:
        return False
    
    # Parse the target URL
    parsed_target = urlparse(target)
    
    # If it's a relative URL, it's safe
    if not parsed_target.scheme and not parsed_target.netloc:
        return True
    
    # If it's an absolute URL, check if it's from the same domain
    try:
        # Get the current host from the request
        current_host = request.host_url.rstrip('/')
        target_host = parsed_target.scheme + '://' + parsed_target.netloc
        
        # Check if the host matches the current host
        if target_host == current_host:
            return True
    except:
        pass
    
    return False

def login_redirect():
    """Redirect user to intended destination after login"""
    # Get the intended URL from the session or request
    intended_url = session.get('intended_url') or request.args.get('next')
    
    # Validate the redirect URL
    if intended_url and is_safe_redirect_url(intended_url):
        # Clear the intended URL from session
        session.pop('intended_url', None)
        return redirect(intended_url)
    
    # Default redirect if no valid intended URL
    return redirect(url_for('dashboard'))

